static void test2(char *msg, char *s0, char *s1, int ordenado) {
  if (verboso)
    printf("%s", msg);
  if (verboso)
    printf("Arreglo es:\n  \"%s\"\n  \"%s\"\n", s0, s1);
  char *str[ ]= { s0, s1 };
  sort(str, 2);
  if ( (  ordenado && (strcmp(str[0], s0)!=0 || strcmp(str[1], s1)!=0) ) ||
